insert  into `newsfr`(`id`,`title`,`description`,`image`,`date`) values 
(1,'Récupération de Personnage','<p style=\"text-align: center;\"><span style=\"text-decoration: underline;\"><span style=\"font-size: 18pt;\"><strong>R&eacute;cup&eacute;ration de Personnage</strong></span></span><br><br><strong>Azeroth Universe propose un service de r&eacute;cup&eacute;ration de personnage en provenance d\'autres serveurs priv&eacute;s/officiel de World of Warcraft.</strong></p>\r\n<p><br><strong><span style=\"text-decoration: underline; font-size: 14pt;\">Comment fonctionne la r&eacute;cup&eacute;ration ?</span></strong></p>\r\n<p>- Vous poss&eacute;dez un personnage sur un autre serveur ?<br>- Vous souhaitez retrouver votre progression sur Azeroth Universe ?<br>- Il vous suffit de faire une demande de r&eacute;cup&eacute;ration en suivant les instructions ci-dessous.</p>\r\n<p><span style=\"text-decoration: underline;\"><strong>Conditions et &eacute;tapes de r&eacute;cup&eacute;ration :<br></strong></span><br>- Une preuve de possession du personnage sera demand&eacute;e (screenshot, vid&eacute;o, armurerie si disponible, etc.).<br>- La r&eacute;cup&eacute;ration se fera avec un &eacute;quipement et un niveau adapt&eacute;s &agrave; nos r&egrave;gles d\'&eacute;quilibrage.<br>- Le transfert de certaines r&eacute;alisations, m&eacute;tiers et montures sera possible selon les crit&egrave;res en place<br><br><span style=\"text-decoration: underline;\"><strong>Pourquoi nous rejoindre ?</strong></span></p>\r\n<p>Azeroth Universe vous offre une exp&eacute;rience de jeu stable, un contenu riche, une communaut&eacute; active et un staff &agrave; l\'&eacute;coute. Ce service de r&eacute;cup&eacute;ration est l\'occasion id&eacute;ale de nous rejoindre sans perdre tout votre temps de jeu accumul&eacute; ailleurs !<br><br><span style=\"text-decoration: underline;\"><strong>Comment faire une demande ?</strong></span></p>\r\n<p>Rendez-vous sur notre Discord : <a title=\"Rejoignez notre communaut&eacute; Discord, l\'endroit id&eacute;al pour trouver ce que vous cherchez !\" href=\"https://discord.com/invite/yDVSxdWFYx\" target=\"_blank\" rel=\"noopener\">Azeroth Universe</a> et ouvrez un ticket dans le salon \"R&eacute;cup&eacute;ration\" depuis la section \"Support\"&nbsp; en fournissant les informations demand&eacute;es. Notre &eacute;quipe traitera votre demande dans les plus brefs d&eacute;lais.<br><br></p>\r\n<p>Rejoignez Azeroth Universe et continuez votre aventure sans attendre !<br><br></p>\r\n<p>&Agrave; tr&egrave;s bient&ocirc;t sur le champ de bataille !</p>\r\n<p>L\'&eacute;quipe d\'Azeroth Universe.</p>','bf19720107870b8eed5a5672254fb646b43a9548.png',1741272833),
(2,'Grade Contributeur','<p><span style=\"text-decoration: underline;\">Azeroth Universe vous propose le grade Contributeur !</span></p>\r\n<p>Le grade Contributeur, qu\'est-ce que c\'est ?</p>\r\n<p>C\'est un grade exclusif qui vous permet de profiter de nombreux avantages en jeu !</p>\r\n<p>Quels sont les bonus en jeu ?<br><br></p>\r\n<p>- Monture (100%) d&egrave;s le niveau 1 pour bien commencer votre aventure.<br>- 50% d\'or en plus lors de la collecte apr&egrave;s chaque monstre tu&eacute;.<br>- Un item pour booster votre progression (Exp x4 x5).<br>- Double d\'exp&eacute;rience le week-end pour progresser plus vite.<br>- Des buffs de caract&eacute;ristiques actifs lorsque vous partez en donjon.<br>- Les Livres de Azeroth Universe utile pour votre aventure.<br>- Une pierre de t&eacute;l&eacute;portation pour vous d&eacute;placer entre les zones.<br>- Une mascotte utile qui vous aide &agrave; atteindre les zones que vous souhaitez explorer.<br>- Un Haut Fait pour r&eacute;compenser votre fid&eacute;lit&eacute; !<br>- Le grade ⬝ Contributeur sur Discord.<br>- Des r&eacute;compenses hebdomadaires !<br>- Une paire d&rsquo;ailes de Diablo 3 pour personnaliser votre personnage.<br>- x4 sacs de 36 emplacements.<br>- Des chemises de t&eacute;l&eacute;portation des Donjons et Raids pour un acc&egrave;s rapide aux lieux essentiels.<br>- Un syst&egrave;me de r&eacute;compenses de Breloques Sup&eacute;rieures, vous permettant de recevoir 10 Breloques Sup&eacute;rieures toutes les 10 minutes.</p>\r\n<p><span style=\"text-decoration: underline;\">Comment obtenir le grade contributeur ?&nbsp;</span></p>\r\n<p>Pour obtenir ce grade, contribuez et soutenez Azeroth Universe. Rendez-vous dans la boutique du jeu, puis dans la section Contributeur.</p>\r\n<p>C\'est une offre &agrave; partir de <strong>2000</strong> Breloques Sup&eacute;rieur.</p>\r\n<p><a href=\"../../../donate\">https://azerothuniverse.org/fr/donate</a><br><br></p>\r\n<p>Merci,<br>L\'&eacute;quipe Azeroth Universe.<br><br><img src=\"http://azerothuniverse.org/news/Contrbiutor2.PNG\" alt=\"\" width=\"303\" height=\"329\">&nbsp;<img src=\"../../../../news/ContributorShop.PNG\" alt=\"\" width=\"1035\" height=\"666\"></p>','f9fec20db8bd976b5fdb1f86fa62ee1292100dd0.png',1741794844),
(3,'Présentation de notre contenu','<p style=\"text-align: center;\"><span class=\"hljs-title\" style=\"font-size: 24pt;\"><span style=\"text-decoration: underline;\">Pr&eacute;sentation de notre contenu</span></span></p>\r\n<p><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">M&eacute;tiers</span> :<br><br></span></strong><strong>Pouvoir apprendre jusqu\'&agrave; <span style=\"text-decoration: underline;\">4 m&eacute;tiers</span> simultan&eacute;ment offre une flexibilit&eacute; pr&eacute;cieuse, permettant de diversifier les comp&eacute;tences et de maximiser la production d&rsquo;objets, d&rsquo;&eacute;quipements ou de consommables.</strong><br><br><img src=\"../../../../news/Skill.png\" alt=\"\" width=\"534\" height=\"537\"><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Affichage des niveaux</span> :</span></strong><br><br><img src=\"../../../../news/LevelDisplay.png\" alt=\"\" width=\"549\" height=\"129\"><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Collections</span> :</span></strong><br><br><img src=\"../../../../news/Collection1.png\" alt=\"\" width=\"503\" height=\"445\">&nbsp;<img src=\"../../../../news/Collection2.png\" alt=\"\" width=\"502\" height=\"445\"><br><img src=\"../../../../news/Collection3.png\" alt=\"\" width=\"501\" height=\"444\">&nbsp;<img src=\"../../../../news/Collection4.png\" alt=\"\" width=\"499\" height=\"442\"><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Boutique du jeu</span> :</span></strong><br><br><img src=\"../../../../news/Shop.png\" alt=\"\" width=\"807\" height=\"518\"><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Syst&egrave;me de Rebirth</span> :<br><br></span>Le Rebirth est un syst&egrave;me con&ccedil;u pour r&eacute;compenser les efforts de votre personnage. Il implique de parcourir &agrave; nouveau les niveaux de 1 &agrave; 80, mais pas seulement ! Il inclut &eacute;galement la progression &agrave; travers les niveaux de Rebirth. &Agrave; chaque niveau de Rebirth atteint, vous b&eacute;n&eacute;ficierez de \"Buffs de caract&eacute;ristiques\" activables &agrave; tout moment &agrave; l\'aide d\'une pierre sp&eacute;ciale appel&eacute;e \"Pierre de Rebirth\". Cette pierre d&eacute;bloquera bien plus que de simples am&eacute;liorations d\'&eacute;tat pour votre personnage. En plus de l\'exp&eacute;rience acquise gr&acirc;ce aux niveaux de Rebirth, vous pourrez collecter des \"Infusions de Vie\" et des \"Explosions de Vie\". Ces &eacute;l&eacute;ments vous permettront d\'obtenir des h&eacute;ritages personnalis&eacute;s et des niveaux suppl&eacute;mentaires.</strong><br><br><img src=\"../../../../news/Rebirth1.png\" alt=\"\" width=\"311\" height=\"383\">&nbsp;<img src=\"../../../../news/Rebirth2.png\" alt=\"\" width=\"311\" height=\"383\">&nbsp;<br><img src=\"../../../../news/Rebirth3.png\" alt=\"\" width=\"312\" height=\"384\"> <img src=\"../../../../news/Rebirth4.png\" alt=\"\" width=\"311\" height=\"383\">&nbsp;<br><img src=\"../../../../news/Rebirth5.png\" alt=\"\" width=\"310\" height=\"382\">&nbsp;<img src=\"../../../../news/Rebirth6.png\" alt=\"\" width=\"311\" height=\"383\"><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Syst&egrave;me de t&eacute;l&eacute;portation</span> :</span></strong><br><br><img src=\"../../../../news/Teleporter1.png\" alt=\"\" width=\"833\" height=\"495\"><br><img src=\"../../../../news/Teleporter2.png\" alt=\"\" width=\"833\" height=\"495\"><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Tableau des H&eacute;ros</span> :</span></strong><br><br><img src=\"../../../../news/QuestHerosA.png\" alt=\"\" width=\"504\" height=\"500\">&nbsp;<img src=\"../../../../news/QuestHerosH.png\" alt=\"\" width=\"503\" height=\"500\"><br><br><span style=\"font-size: 14pt;\"><strong><span style=\"text-decoration: underline;\">Syst&egrave;me de Talent</span> :</strong></span><br><br><span style=\"font-size: 14pt;\"><strong><span style=\"text-decoration: underline;\">Classes Custom</span></strong></span> : <strong>Moine, Chasseur de d&eacute;mons, Mage de combat sanglant...</strong><br><br><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Moine</span> :</span></strong><br><br><img src=\"../../../../news/Monk.png\" alt=\"\" width=\"733\" height=\"410\">&nbsp;<img src=\"../../../../news/MonkButton.png\" alt=\"\" width=\"295\" height=\"167\"><br><br><span style=\"font-size: 14pt;\"><strong style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Chasseur de d&eacute;mons</span> :<br><br><img src=\"../../../../news/DemonHunter.png\" alt=\"\" width=\"737\" height=\"413\">&nbsp;<img src=\"../../../../news/DemonHunterButton.png\" alt=\"\" width=\"302\" height=\"157\"><br><br></strong><strong><span style=\"text-decoration: underline;\">Mage de combat sanglant</span> :</strong><br><br><strong style=\"font-size: medium;\"><img src=\"../../../../news/BloodBattleMage.png\" alt=\"\" width=\"731\" height=\"405\">&nbsp;<img src=\"../../../../news/BloodBattleMageButton.png\" alt=\"\" width=\"306\" height=\"161\"></strong><br><br><strong><span style=\"text-decoration: underline; font-size: 14pt;\">Choix de l\'histoire</span> :</strong><br><br><strong style=\"font-size: medium;\"><img src=\"../../../../news/History.png\" alt=\"\" width=\"768\" height=\"449\"></strong><br><br><strong><span style=\"text-decoration: underline;\">Syst&egrave;me d\'arme prodigieuse</span> :</strong><br><br><strong style=\"font-size: medium;\"><img src=\"../../../../news/Prodi1.png\" alt=\"\" width=\"719\" height=\"515\">&nbsp;</strong><br><br><strong><span style=\"text-decoration: underline;\">&Eacute;quipement H&eacute;ritage</span> :</strong><br><br><strong><img src=\"../../../../news/Heirloom.png\" alt=\"\" width=\"674\" height=\"416\"></strong><br><br><strong><span style=\"text-decoration: underline;\">Modificateur d\'exp&eacute;rience</span> :</strong><br><br><strong><img src=\"../../../../news/ExpRate.png\" alt=\"\" width=\"312\" height=\"487\"></strong><br><br><strong><span style=\"text-decoration: underline;\">Syst&egrave;me de Bot</span> :</strong><br><br><strong><img src=\"../../../../news/Bot1.png\" alt=\"\" width=\"338\" height=\"425\">&nbsp;<img src=\"../../../../news/Bot2.png\" alt=\"\" width=\"336\" height=\"423\"></strong><br><strong><img src=\"../../../../news/Bot3.png\" alt=\"\" width=\"336\" height=\"423\">&nbsp;<img src=\"../../../../news/Bot4.png\" alt=\"\" width=\"335\" height=\"422\"></strong><br><strong><img src=\"../../../../news/Bot5.png\" alt=\"\" width=\"334\" height=\"420\">&nbsp;<img src=\"../../../../news/Bot6.png\" alt=\"\" width=\"331\" height=\"416\"></strong><br><br><strong><span style=\"text-decoration: underline;\">Un nouveau destin</span> :</strong><br><br><strong><img src=\"../../../../news/Destiny1.png\" alt=\"\" width=\"688\" height=\"425\"></strong><br><strong><img src=\"../../../../news/Destiny2.png\" alt=\"\" width=\"710\" height=\"438\"></strong><br><br><strong><span style=\"text-decoration: underline;\">Ramassage de zone</span>&nbsp;:</strong><br><br><strong><img src=\"../../../../news/FarmZone.png\" alt=\"\" width=\"714\" height=\"575\"></strong><br></span></p>','39d778e4af5cd2a55c07ce234707fc849bfbd359.png',1741100033),
(4,'Guide de démarrage','<p style=\"text-align: center;\"><span style=\"text-decoration: underline;\"><span style=\"font-size: 18pt;\"><strong>Guide de d&eacute;marrage<br></strong></span></span><strong>(Anciennement Syphrena)</strong><br><br><a href=\"https://docs.google.com/document/d/1kg_if-Jn3XotzBFeDGrZDphfEvdUbHR875X0ltZdNc4/edit?usp=sharing\" target=\"_blank\" rel=\"noopener\">https://docs.google.com/document/d/1kg_if-Jn3XotzBFeDGrZDphfEvdUbHR875X0ltZdNc4/edit?usp=sharing</a></p>','d4e7145e550f14866da0c09e4df2b1833dfe299e.jpg',1741013633),
(5,'#1 Event','<p style=\"text-align: center;\"><strong><span style=\"text-decoration: underline;\"><span style=\"font-size: 18pt;\">&Eacute;v&eacute;nement &agrave; venir sur Azeroth Universe !</span></span></strong><br><br><span style=\"font-size: 14pt;\">Aper&ccedil;u de l&rsquo;&eacute;v&eacute;nement &agrave; venir sur Azeroth Universe !</span><br><span style=\"font-size: 14pt;\"><span style=\"font-size: 14pt;\">L&rsquo;&eacute;v&eacute;nement approche &agrave; grands pas, et voici un petit aper&ccedil;u de ce qui vous attend !&nbsp;</span><br><br><span style=\"text-decoration: underline;\"><span style=\"font-size: 18.6667px;\">Rejoignez-nous d&egrave;s maintenant !</span></span><br><span style=\"font-size: 18.6667px;\">Discord : <a href=\"https://discord.com/invite/yDVSxdWFYx\">Azeroth universe</a></span></span></p>\r\n<p><br><iframe src=\"https://www.youtube.com/embed/FGVhzbsVfQ4\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe></p>','2b9db592eb61df6630867d8873dc42d4375c13ab.jpg',1740927233),
(6,'Nous Recrutons !','<p style=\"text-align: center;\"><span style=\"text-decoration: underline; font-size: 18pt;\">Recrutement chez Azeroth Universe<br></span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 24px;\">Rejoignez-nous d&egrave;s maintenant !</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 14pt;\">Discord :&nbsp;<a title=\"Rejoignez notre communaut&eacute; Discord, l\'endroit id&eacute;al pour trouver ce que vous cherchez !\" href=\"https://discord.com/invite/yDVSxdWFYx\">Azeroth universe</a></span></p>\r\n<p style=\"text-align: center;\"><span style=\"text-decoration: underline; font-size: 18pt;\"><br><img src=\"http://azerothuniverse.org/news/Recrut.png\" alt=\"\" width=\"926\" height=\"833\"><br></span></p>','0a12461a4d7249ea2b7e5143ff20730820abda7b.jpg',1740840833),
(7,'Conversion des Breloques','<p style=\"text-align: center;\"><span style=\"text-decoration: underline;\"><span style=\"font-size: 24px;\"><strong><u>Conversion des Breloques Inf&eacute;rieures en Breloques Sup&eacute;rieures</u></strong></span></span></p>\r\n<h3 data-pm-slice=\"1 1 []\"><span style=\"text-decoration: underline;\"><span style=\"font-size: 14pt;\">Comment &ccedil;a fonctionne ?</span><br></span></h3>\r\n<ul data-spread=\"false\" data-pm-slice=\"3 3 []\">\r\n<li>\r\n<p>&Agrave; chaque connexion, notre syst&egrave;me v&eacute;rifiera si vous poss&eacute;dez des Breloques Inf&eacute;rieures.</p>\r\n</li>\r\n</ul>\r\n<ul data-spread=\"false\" data-pm-slice=\"3 3 []\">\r\n<li>\r\n<p>Si c\'est le cas, elles seront automatiquement converties en Breloques Sup&eacute;rieures &agrave; un taux &eacute;gal !</p>\r\n</li>\r\n</ul>\r\n<ul data-spread=\"false\" data-pm-slice=\"3 3 []\">\r\n<li>\r\n<p><span style=\"text-decoration: underline; color: #e03e2d;\">Vous n\'avez rien &agrave; faire, le syst&egrave;me s&rsquo;occupe de tout pour vous.<br></span></p>\r\n</li>\r\n</ul>\r\n<h3 data-pm-slice=\"1 3 []\"><span style=\"text-decoration: underline;\">Comment obtenir des Breloques Inf&eacute;rieures ?</span></h3>\r\n<ul>\r\n<li>Vous pouvez obtenir des Breloques Inf&eacute;rieures en votant pour le serveur depuis la page suivante : <a title=\"Votez Ici !\" href=\"../../vote\" target=\"_blank\" rel=\"noopener\">Votez ici</a>.<br><br></li>\r\n<li>Chaque vote vous r&eacute;compense et vous permet d\'accumuler ces pr&eacute;cieuses breloques !</li>\r\n</ul>\r\n<h3 data-pm-slice=\"1 3 []\"><span style=\"text-decoration: underline;\">Comment obtenir des Breloques Sup&eacute;rieures ?</span></h3>\r\n<ul>\r\n<li>Vous pouvez obtenir des Breloques Sup&eacute;rieures en contribuant pour le serveur depuis la page suivante :&nbsp;<a title=\"Contribuer ici\" href=\"../../../donate\" target=\"_blank\" rel=\"noopener\">Contribuer ici</a>.<br><br></li>\r\n<li>Chaque don vous r&eacute;compense et vous permet d\'accumuler ces pr&eacute;cieuses breloques !</li>\r\n</ul>\r\n<h3 data-pm-slice=\"1 3 []\"><span style=\"text-decoration: underline;\">Comment convertir des Breloques Sup&eacute;rieures ?</span></h3>\r\n<ul>\r\n<li>Une fois vos Breloques Sup&eacute;rieures obtenues, vous devrez vous rendre directement aupr&egrave;s de la banque en jeu pour les convertir en Breloques Sup&eacute;rieures du jeu sous forme d\'objets. Une fois ces Breloques Sup&eacute;rieures du jeu obtenues, vous pourrez les d&eacute;penser dans les zones cosm&eacute;tiques ou dans la boutique du jeu pour personnaliser votre exp&eacute;rience de mani&egrave;re unique !<br><br><img src=\"../../../../news/PanelIco.png\" alt=\"\" width=\"53\" height=\"50\"><br><br><img src=\"../../../../news/NPCConvertH.PNG\" alt=\"\" width=\"807\" height=\"447\"><br><br><img src=\"../../../../news/NPCConvertA.PNG\" alt=\"\" width=\"807\" height=\"456\"></li>\r\n</ul>','f84c77d58c3c9f3375703dc9ff0a35958a0ac38a.jpg',1740754433),
(8,'Trailer','<p style=\"text-align: center;\"><span style=\"text-decoration: underline;\"><span style=\"font-size: 18pt;\"><strong>Azeroth Universe Trailer</strong></span></span><br><br><iframe src=\"https://www.youtube.com/embed/IlwdlcN0sOs\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe></p>','47daeed5c80a55ba12119991b442342f168d8304.png',1741617027),
(9,'Présentation des races','<p style=\"text-align: center;\"><span style=\"font-size: 18pt;\"><strong><u>Pr&eacute;sentation des races</u></strong></span></p>\r\n<p><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">Cr&eacute;ation de personnage</span>&nbsp;:<br></span></strong></p>\r\n<p><strong>Plongez dans une exp&eacute;rience unique avec un large &eacute;ventail de choix pour fa&ccedil;onner votre personnage !<br></strong><strong>Toutes les races de Shadowlands sont disponibles, vous permettant d\'incarner votre personnage favori.</strong></p>\r\n<p><span style=\"font-size: 14pt;\"><strong><span style=\"text-decoration: underline;\">Nouvelles classes custom exclusives</span>&nbsp;:</strong></span></p>\r\n<p><strong><span style=\"text-decoration: underline;\">Moine</span>&nbsp;: Ma&icirc;tre des arts martiaux, il canalise son chi pour infliger des d&eacute;g&acirc;ts ou soigner ses alli&eacute;s.<br></strong><strong><span style=\"text-decoration: underline;\">Chasseur de D&eacute;mon</span>&nbsp;: Un combattant redoutable ma&icirc;trisant la magie gangren&eacute;e et la m&eacute;tamorphose.<br></strong><strong><span style=\"text-decoration: underline;\">Mage de Combat Sanglant</span>&nbsp;: Un mage hybride qui manipule la magie du sang pour renforcer ses sorts destructeurs.<br><span style=\"text-decoration: underline;\">H&eacute;ros</span>&nbsp;: Une classe in&eacute;dite avec des capacit&eacute;s polyvalentes pour s&rsquo;adapter &agrave; tous les styles de jeu.</strong><br><br><span style=\"font-size: 14pt;\"><strong><u>Prochaines sorties de classes</u></strong><strong>&nbsp;</strong><span style=\"font-weight: bold;\">:</span></span><br><br><strong><span style=\"text-decoration: underline;\">&Eacute;vocateur</span> : <span style=\"color: #e03e2d;\">Disponible prochainement</span></strong><span style=\"text-decoration: underline;\"><span style=\"color: #e03e2d; text-decoration: underline;\"><br></span><strong>Cavalier</strong></span><strong> :&nbsp;</strong><strong><span style=\"color: #e03e2d;\">Disponible</span></strong><strong><span style=\"color: #e03e2d;\">&nbsp;prochainement</span></strong><strong><span style=\"text-decoration: underline;\"><span style=\"color: #e03e2d; text-decoration: underline;\"><br></span></span></strong><strong><span style=\"text-decoration: underline;\">Dompteur</span> :&nbsp;</strong><strong><span style=\"color: #e03e2d;\">Disponible</span></strong><strong><span style=\"color: #e03e2d;\">&nbsp;prochainement</span></strong><strong><br><br><iframe src=\"https://www.youtube.com/embed/mZdIpJkYVGw\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe><br><br><iframe src=\"https://www.youtube.com/embed/PVdH1Hsa6mU\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe><br><br><iframe src=\"https://www.youtube.com/embed/xeTX0LQ_d0U\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe><br><br><iframe src=\"https://www.youtube.com/embed/WmMdhbgi5BA\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe><br><br><iframe src=\"https://www.youtube.com/embed/BZ2bG6apus0\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe><br><br><iframe src=\"https://www.youtube.com/embed/Wsi4ZH8Rg60\" width=\"560\" height=\"314\" allowfullscreen=\"allowfullscreen\"></iframe><br></strong></p>','f811e191fe58c07c6f901c02830d3541900817bb.jpg',1741623790),
(10,'Sésame de bienvenue','<p style=\"text-align: center;\"><strong><span style=\"font-size: 14pt;\"><span style=\"text-decoration: underline;\">S&eacute;same de bienvenue</span>&nbsp;: Niveau (<span style=\"color: #f1c40f;\">80</span>)<br><br></span>Id&eacute;al pour ceux qui souhaitent plonger rapidement dans le contenu de haut niveau, ce s&eacute;same offre un &eacute;quipement adapt&eacute; et un acc&egrave;s imm&eacute;diat aux zones et activit&eacute;s correspondantes. Que vous soyez un nouveau venu ou un v&eacute;t&eacute;ran souhaitant tester une nouvelle classe, ce boost est parfait pour explorer l\'univers d\'Azeroth sans attendre.<br><br><img src=\"../../../news/NPCSesame.png\" alt=\"\" width=\"334\" height=\"542\"> &nbsp;<img src=\"../../../news/Sesame80.png\" alt=\"\" width=\"437\" height=\"543\"><br></strong></p>','f294e9137e713c81308bd0c4ef95bc1a59a3da01.png',1741624857);
