insert  into `store_items`(`id`,`name`,`description`,`category`,`type`,`price_type`,`dp`,`vp`,`icon`,`command`) values 
(25,'Name Change','Give yourself a (new) name!\nThe name you chose when creating your character is not set in stone for eternity. Who hasn\'t dreamed of adopting a new identity and starting fresh in the morning dew? For your character, it\'s possible!',4,4,2,0,30,'vas_namechange','.character rename'),
(28,'Race Change','Because becoming a gnome is really cool!\nIt\'s not always easy to have five fingers on each hand, pointy ears, greenish skin, or to find yourself covered in rough hair every time you bump your knee on a table corner. Sometimes, we\'d like to change everything. Rejoice: it\'s possible!',4,7,2,0,60,'vas_racechange','.character changerace'),
(29,'Faction Change','Effects of faction change:\nThe faction change service allows you to switch a character\'s faction. You will then need to choose a new race, a new appearance, and a new name. However, you must choose a race compatible with your current class.',4,6,2,0,60,'vas_factionchange','.character changefaction'),
(30,'Appearance Change','Customize your character: Face Skin, Face, Hairstyle, Hairstyle Color, Details.',4,5,2,0,30,'vas_appearancechange','.character customize'),
