insert  into `store_itemsfr`(`id`,`name`,`description`,`category`,`type`,`price_type`,`dp`,`vp`,`icon`,`command`) values 
(25,'Changement de Nom','Faites-vous un (nouveau) nom !\nLe nom que vous avez choisi à la création de votre personnage n’est pas voué à rester gravé dans le marbre pour l’éternité. Qui n’a jamais rêvé de revêtir une nouvelle identité pour repartir à zéro dans la fraîche rosée du matin ? Pour votre personnage, c’est possible !',4,4,1,30,0,'vas_namechange','.character rename'),
(28,'Changement de Race','Parce que devenir un gnome, c’est vraiment la classe !\nCe n’est pas tous les jours facile d’avoir cinq doigts à chaque main, des oreilles pointues, la peau verdâtre ou de se retrouver couvert de poils rêches à chaque fois que vous vous cognez le genou sur un coin de table. Parfois, on aimerait pouvoir tout changer. Réjouissez-vous : c’est possible !',4,7,1,60,0,'vas_racechange','.character changerace'),
(29,'Changement de Faction','Effets d’un changement de faction :\nLe service de changement de faction vous permet de changer un personnage de faction. Vous devrez alors choisir une nouvelle race, une nouvelle apparence ainsi qu’un nouveau nom. Vous devrez toutefois choisir une race compatible avec votre classe actuelle.',4,6,1,60,0,'vas_factionchange','.character changefaction'),
(30,'Changement Apparence','Personnaliser votre personnage: Peau du Visage, Visage, Coiffure, Couleur Coiffure, Details.',4,5,1,30,0,'vas_appearancechange','.character customize'),
